module counter_8bit(clk, rst, en, count);
    input clk;
    input rst;
    input en;
    output reg [7:0] count;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst) begin
            count <= 0;
        end else if (en) begin
            count <= count + 1;
        end
    end
endmodule
